const cached = $('Verificar Cache').first().json;
return [{ json: {
  success: true,
  answer: cached.answer,
  intent: cached.intent_category,
  source: 'cache'
}}];

const items = $('Cargar Knowledge Base').all();
const trigger = $('Trigger - Execute Workflow').first().json;

if (!items || items.length === 0 || !items[0].json.kb_type) {
  return [{ json: { hasData: false, question: trigger.question, clinic_id: trigger.clinic_id, language: trigger.language || 'es' } }];
}

const kb = items.map(i => i.json);
const context = {
  services: kb.filter(r => r.kb_type === 'services').map(r => r.content).join('\n'),
  pricing: kb.filter(r => r.kb_type === 'pricing').map(r => r.content).join('\n'),
  schedule: kb.filter(r => r.kb_type === 'schedule').map(r => r.content).join('\n'),
  faq: kb.filter(r => r.kb_type === 'faq').map(r => r.content).join('\n'),
  location: kb.filter(r => r.kb_type === 'location').map(r => r.content).join('\n'),
  policies: kb.filter(r => r.kb_type === 'policies').map(r => r.content).join('\n'),
  team: kb.filter(r => r.kb_type === 'team').map(r => r.content).join('\n')
};

return [{ json: { hasData: true, context, question: trigger.question, clinic_id: trigger.clinic_id, language: trigger.language || 'es' } }];

const clinic = $('Obtener Contacto Clinica').first().json;
const clinicName = clinic.name || 'la clinica';
return [{ json: {
  success: true,
  answer: 'Lo siento, no tengo informacion disponible en este momento. Te recomiendo contactar directamente con ' + clinicName + ' para resolver tu consulta.',
  intent: 'fallback',
  source: 'default'
}}];

parameters.text:
=Clasifica la siguiente pregunta en una de estas categorias: services | pricing | schedule | faq | location | policies | general
Pregunta: {{ $json.question }}
Responde SOLO con la categoria, sin mas texto.

messageValues.message:
=Eres el asistente virtual de la clinica. Responde UNICAMENTE basandote en la informacion proporcionada en el contexto. Si la informacion no esta disponible en el contexto, di exactamente: 'No tengo esa informacion disponible, te recomiendo contactar directamente con la clinica.'

NO inventes precios, horarios ni servicios. Se conciso y amigable.
Responde siempre en el mismo idioma que la pregunta.

CONTEXTO DE LA CLINICA:
Servicios: {{ $('Formatear y Verificar KB').first().json.context.services }}
Precios: {{ $('Formatear y Verificar KB').first().json.context.pricing }}
Horarios: {{ $('Formatear y Verificar KB').first().json.context.schedule }}
FAQ: {{ $('Formatear y Verificar KB').first().json.context.faq }}
