parameters.jsCode:
const genResult = $('Generar Respuesta').first().json;
const answer = genResult.text || genResult.output || genResult.response || '';
const question = $('Formatear y Verificar KB').first().json.question;
const intentResult = $('Clasificar Intencion').first().json;
const intent = (intentResult.text || intentResult.output || intentResult.response || 'general').trim().toLowerCase();

const hallucinationPatterns = ['segun mis datos', 'estimo que', 'aproximadamente', 'creo que podria', 'es posible que'];
let finalAnswer = answer;
let wasFiltered = false;

for (const pattern of hallucinationPatterns) {
  if (finalAnswer.toLowerCase().includes(pattern)) {
    finalAnswer = 'No tengo esa informacion disponible con certeza. Te recomiendo contactar directamente con la clinica para obtener datos exactos.';
    wasFiltered = true;
    break;
  }
}

if (finalAnswer.length > 500) {
  finalAnswer = finalAnswer.substring(0, 497) + '...';
}

return [{ json: {
  answer: finalAnswer,
  intent: intent,
  question: question,
  wasFiltered: wasFiltered,
  clinic_id: $('Trigger - Execute Workflow').first().json.clinic_id
}}];
